"use client";
import { cn } from "@/lib/utils";
import React, { useState } from "react";
import { motion } from "motion/react";

export interface AnimatedTabsProps {
  tabs: {
    id: string;
    label: string;
    content?: React.ReactNode;
  }[];
  className?: string;
  tabClassName?: string;
  activeTabClassName?: string;
  contentClassName?: string;
  onChange?: (id: string) => void;
  theme?: "light" | "dark";
}

export function AnimatedTabs({
  tabs,
  className,
  tabClassName,
  activeTabClassName,
  contentClassName,
  onChange,
  theme = "dark",
}: AnimatedTabsProps) {
  const [activeTab, setActiveTab] = useState(tabs[0]?.id);
  const isDark = theme === "dark";

  const handleTabClick = (id: string) => {
    setActiveTab(id);
    onChange?.(id);
  };

  return (
    <div className={cn("w-full", className)}>
      <div role="tablist" className={cn("relative flex items-center gap-1 rounded-lg p-1 border", isDark ? "bg-neutral-900/50 border-neutral-800" : "bg-neutral-100 border-neutral-200")}>
        {tabs.map((tab) => (
          <button
            key={tab.id}
            role="tab"
            aria-selected={activeTab === tab.id}
            onClick={() => handleTabClick(tab.id)}
            className={cn(
              "relative z-10 flex-1 rounded-md px-4 py-2 text-sm font-medium transition-colors duration-200",
              activeTab === tab.id
                ? cn(isDark ? "text-white" : "text-neutral-900", activeTabClassName)
                : isDark ? "text-neutral-400 hover:text-neutral-200" : "text-neutral-600 hover:text-neutral-900",
              tabClassName
            )}
          >
            {activeTab === tab.id && (
              <motion.div
                layoutId="animated-tab-pill"
                className={cn("absolute inset-0 rounded-md border", isDark ? "bg-neutral-800 border-neutral-700" : "bg-white border-neutral-300 shadow-sm")}
                transition={{
                  type: "spring",
                  stiffness: 500,
                  damping: 35,
                }}
              />
            )}
            <span className="relative z-10">{tab.label}</span>
          </button>
        ))}
      </div>

      {tabs.map((tab) =>
        tab.content && activeTab === tab.id ? (
          <motion.div
            key={tab.id}
            role="tabpanel"
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -10 }}
            transition={{ type: "spring", stiffness: 300, damping: 30 }}
            className={cn("mt-4", contentClassName)}
          >
            {tab.content}
          </motion.div>
        ) : null
      )}
    </div>
  );
}

import { type ClassValue, clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
    return twMerge(clsx(inputs));
}

"use client";
import { cn } from "@/lib/utils";
import React, { useRef, useState, useCallback } from "react";
import { motion, useMotionValue, useSpring } from "motion/react";

export interface MagneticButtonProps {
  children: React.ReactNode;
  className?: string;
  magneticStrength?: number;
  magneticRadius?: number;
  onClick?: () => void;
  disabled?: boolean;
  theme?: "light" | "dark";
}

export function MagneticButton({
  children,
  className,
  magneticStrength = 0.3,
  magneticRadius = 150,
  onClick,
  disabled = false,
  theme: _theme = "dark",
}: MagneticButtonProps) {
  const ref = useRef<HTMLButtonElement>(null);
  const [isHovering, setIsHovering] = useState(false);

  const springConfig = { stiffness: 200, damping: 15, mass: 0.5 };
  const x = useSpring(useMotionValue(0), springConfig);
  const y = useSpring(useMotionValue(0), springConfig);

  const handleMouseMove = useCallback(
    (e: React.MouseEvent) => {
      if (!ref.current || disabled) return;
      const rect = ref.current.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;

      const distX = e.clientX - centerX;
      const distY = e.clientY - centerY;
      const distance = Math.sqrt(distX * distX + distY * distY);

      if (distance < magneticRadius) {
        x.set(distX * magneticStrength);
        y.set(distY * magneticStrength);
      }
    },
    [disabled, magneticRadius, magneticStrength, x, y]
  );

  const handleMouseLeave = useCallback(() => {
    setIsHovering(false);
    x.set(0);
    y.set(0);
  }, [x, y]);

  return (
    <motion.button
      ref={ref}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovering(true)}
      onMouseLeave={handleMouseLeave}
      onClick={onClick}
      disabled={disabled}
      style={{ x, y }}
      whileTap={{ scale: 0.95 }}
      className={cn(
        "relative inline-flex items-center justify-center rounded-xl bg-gradient-to-b from-neutral-800 to-neutral-900 px-8 py-3 text-sm font-medium text-white shadow-lg transition-shadow duration-300",
        isHovering && "shadow-xl shadow-purple-500/20",
        disabled && "opacity-50 cursor-not-allowed",
        className
      )}
    >
      <motion.span
        animate={isHovering ? { scale: 1.05 } : { scale: 1 }}
        transition={{ type: "spring", stiffness: 400, damping: 20 }}
        className="relative z-10"
      >
        {children}
      </motion.span>

      {/* Glow effect on hover */}
      <motion.div
        className="absolute inset-0 rounded-xl bg-gradient-to-r from-purple-600/20 to-pink-600/20"
        animate={{ opacity: isHovering ? 1 : 0 }}
        transition={{ duration: 0.3 }}
      />
    </motion.button>
  );
}

