"use client";
import { cn } from "@/lib/utils";
import React, { useState, useEffect } from "react";

export interface MeteorsCardProps {
  children: React.ReactNode;
  className?: string;
  meteorCount?: number;
  meteorColor?: string;
  theme?: "light" | "dark";
}

export function MeteorsCard({
  children,
  className,
  meteorCount = 20,
  meteorColor = "white",
  theme = "dark",
}: MeteorsCardProps) {
  return (
    <div
      className={cn(
        "relative overflow-hidden rounded-xl border p-8",
        theme === "dark" ? "border-neutral-800 bg-neutral-950" : "border-neutral-200 bg-white",
        className
      )}
    >
      <Meteors count={meteorCount} color={meteorColor} />
      <div className="relative z-10">{children}</div>
    </div>
  );
}

interface MeteorData {
  left: string;
  delay: string;
  duration: string;
  size: number;
  tailWidth: number;
}

function generateMeteors(count: number): MeteorData[] {
  return Array.from({ length: count }).map(() => ({
    left: `${Math.random() * 100}%`,
    delay: `${Math.random() * 5}s`,
    duration: `${Math.random() * 3 + 2}s`,
    size: Math.random() * 1.5 + 0.5,
    tailWidth: Math.random() * 80 + 40,
  }));
}

function Meteors({ count, color }: { count: number; color: string }) {
  // Start empty so SSR markup matches the first client render; randomised
  // positions are generated post-mount to avoid a hydration mismatch.
  const [meteors, setMeteors] = useState<MeteorData[]>([]);

  useEffect(() => {
    setMeteors(generateMeteors(count));
  }, [count]);

  return (
    <>
      {meteors.map((m, i) => (
        <span
          key={i}
          className="absolute top-0 rotate-[215deg] animate-meteor"
          style={{
            left: m.left,
            animationDelay: m.delay,
            animationDuration: m.duration,
          }}
        >
          <span
            className="block rounded-full"
            style={{
              width: `${m.size}px`,
              height: `${m.size}px`,
              backgroundColor: color,
              boxShadow: `0 0 ${m.size * 4}px ${m.size}px ${color}`,
            }}
          />
          <span
            className="absolute top-1/2 -translate-y-1/2 -left-[1px]"
            style={{
              width: `${m.tailWidth}px`,
              height: `${m.size * 0.8}px`,
              background: `linear-gradient(to left, ${color}, transparent)`,
              opacity: 0.6,
            }}
          />
        </span>
      ))}
    </>
  );
}

