"use client";
import { cn } from "@/lib/utils";
import React, { useState, useCallback, useEffect, useRef } from "react";
import { createPortal } from "react-dom";
import { motion, AnimatePresence } from "motion/react";

export type NotificationType = "success" | "error" | "warning" | "info";

export interface Notification {
  id: string;
  title: string;
  description?: string;
  type?: NotificationType;
  duration?: number;
}

export interface NotificationStackProps {
  className?: string;
  position?: "top-right" | "top-left" | "bottom-right" | "bottom-left";
  maxVisible?: number;
  theme?: "light" | "dark";
  /**
   * When true (default), renders the stack with `createPortal` on `document.body` so it sits above
   * app chrome (headers, overflow-hidden previews). Set false only for special embed cases.
   */
  usePortal?: boolean;
}

const typeStyles: Record<NotificationType, string> = {
  success: "border-green-800/50 bg-green-950/80",
  error: "border-red-800/50 bg-red-950/80",
  warning: "border-yellow-800/50 bg-yellow-950/80",
  info: "border-blue-800/50 bg-blue-950/80",
};

const typeIcons: Record<NotificationType, string> = {
  success: "✓",
  error: "✕",
  warning: "⚠",
  info: "ℹ",
};

const typeIconColors: Record<NotificationType, string> = {
  success: "text-green-400",
  error: "text-red-400",
  warning: "text-yellow-400",
  info: "text-blue-400",
};

const positionStyles: Record<string, string> = {
  "top-right": "top-4 right-4",
  "top-left": "top-4 left-4",
  "bottom-right": "bottom-4 right-4",
  "bottom-left": "bottom-4 left-4",
};

// Hook for managing notifications
export function useNotifications() {
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback(
    (notification: Omit<Notification, "id">) => {
      const id = Math.random().toString(36).substring(2, 9);
      setNotifications((prev) => [...prev, { ...notification, id }]);
      return id;
    },
    []
  );

  const removeNotification = useCallback((id: string) => {
    setNotifications((prev) => prev.filter((n) => n.id !== id));
  }, []);

  const clearAll = useCallback(() => {
    setNotifications([]);
  }, []);

  return { notifications, addNotification, removeNotification, clearAll };
}

export function NotificationStack({
  className,
  position = "top-right",
  maxVisible = 5,
  theme = "dark",
  usePortal = true,
  notifications,
  onRemove,
}: NotificationStackProps & {
  notifications: Notification[];
  onRemove: (id: string) => void;
}) {
  const visible = notifications.slice(-maxVisible);
  const isBottom = position.startsWith("bottom");
  const canUseDom = typeof document !== "undefined";

  const stack = (
    <div
      className={cn(
        "fixed z-[1000] flex flex-col gap-2 w-[380px] max-w-[calc(100vw-2rem)] pointer-events-none",
        positionStyles[position],
        isBottom && "flex-col-reverse",
        className
      )}
    >
      <AnimatePresence mode="popLayout">
        {visible.map((notification) => (
          <NotificationItem
            key={notification.id}
            notification={notification}
            onRemove={onRemove}
            position={position}
            theme={theme}
          />
        ))}
      </AnimatePresence>
    </div>
  );

  if (!usePortal) {
    return stack;
  }

  if (!canUseDom) {
    return null;
  }

  return createPortal(stack, document.body);
}

function NotificationItem({
  notification,
  onRemove,
  position,
  theme = "dark",
}: {
  notification: Notification;
  onRemove: (id: string) => void;
  position: string;
  theme?: "light" | "dark";
}) {
  const { id, title, description, type = "info", duration = 5000 } = notification;
  const [_progress, setProgress] = useState(100);
  const timeoutRef = useRef<number | null>(null);

  useEffect(() => {
    if (duration <= 0) return;

    timeoutRef.current = window.setTimeout(() => {
      onRemove(id);
      setProgress(0);
    }, duration);

    return () => {
      if (timeoutRef.current !== null) {
        clearTimeout(timeoutRef.current);
      }
    };
  }, [id, duration, onRemove]);

  const isRight = position.includes("right");

  return (
    <motion.div
      layout
      initial={{
        opacity: 0,
        x: isRight ? 100 : -100,
        scale: 0.95,
      }}
      animate={{
        opacity: 1,
        x: 0,
        scale: 1,
      }}
      exit={{
        opacity: 0,
        x: isRight ? 100 : -100,
        scale: 0.95,
        transition: { duration: 0.2 },
      }}
      transition={{
        type: "spring",
        stiffness: 400,
        damping: 30,
      }}
      role="status"
      className={cn(
        "pointer-events-auto relative overflow-hidden rounded-lg border backdrop-blur-md p-4 shadow-2xl",
        typeStyles[type]
      )}
    >
      <div className="flex items-start gap-3">
        <span className={cn("text-lg mt-0.5 font-bold", typeIconColors[type])}>
          {typeIcons[type]}
        </span>
        <div className="flex-1 min-w-0">
          <p className={cn("text-sm font-semibold", theme === "dark" ? "text-white" : "text-neutral-900")}>{title}</p>
          {description && (
            <p className={cn("text-xs mt-1", theme === "dark" ? "text-neutral-400" : "text-neutral-600")}>{description}</p>
          )}
        </div>
        <button
          onClick={() => onRemove(id)}
          aria-label={`Dismiss ${title} notification`}
          className={cn("flex-shrink-0 transition-colors text-sm", theme === "dark" ? "text-neutral-500 hover:text-white" : "text-neutral-600 hover:text-neutral-900")}
        >
          ✕
        </button>
      </div>

      {/* Progress bar */}
      {duration > 0 && (
        <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-neutral-800">
          <motion.div
            className={cn(
              "h-full",
              type === "success" && "bg-green-500",
              type === "error" && "bg-red-500",
              type === "warning" && "bg-yellow-500",
              type === "info" && "bg-blue-500"
            )}
            initial={{ width: "100%" }}
            animate={{ width: "0%" }}
            transition={{ duration: duration / 1000, ease: "linear" }}
          />
        </div>
      )}
    </motion.div>
  );
}

