"use client";
import React, { useRef } from "react";
import { motion, useInView } from "motion/react";
import { cn } from "@/lib/utils";

// ─── Constants ─────────────────────────────────────────────────────────────────

const DOT_SIZE = 28;
const LINE_LEFT = DOT_SIZE / 2;

// ─── Types ──────────────────────────────────────────────────────────────────────

export interface TimelineItem {
  id: string;
  title: string;
  description?: string;
  date?: string;
  icon?: React.ReactNode;
  /** Per-item accent color for the circle, glow, and connecting line */
  color?: string;
}

export interface AnimatedTimelineProps {
  items: TimelineItem[];
  className?: string;
  /** Fallback line color when an item has no color */
  lineColor?: string;
  /**
   * Layout / animation variant:
   * - "vertical"    — staggered slide-from-left with colored circles and ripple (default)
   * - "horizontal"  — left-to-right with growing connecting line
   * - "cards"       — alternating left/right slide-in cards
   * - "steps"       — numbered progress steps with radial fill on entry
   */
  variant?: "vertical" | "horizontal" | "cards" | "steps";
  /** @deprecated Use variant="horizontal" instead */
  orientation?: "vertical" | "horizontal";
  theme?: "light" | "dark";
}

// ─── Main component ──────────────────────────────────────────────────────────

export function AnimatedTimeline({
  items,
  className,
  lineColor = "rgba(255,255,255,0.08)",
  variant,
  orientation = "vertical",
  theme = "dark",
}: AnimatedTimelineProps) {
  // Support legacy orientation prop. variant takes precedence.
  const resolvedVariant = variant ?? (orientation === "horizontal" ? "horizontal" : "vertical");
  const resolvedLineColor = theme === "light" ? "rgba(0,0,0,0.08)" : lineColor;

  if (resolvedVariant === "horizontal") {
    return <HorizontalTimeline items={items} className={className} lineColor={resolvedLineColor} />;
  }
  if (resolvedVariant === "cards") {
    return <CardsTimeline items={items} className={className} lineColor={resolvedLineColor} />;
  }
  if (resolvedVariant === "steps") {
    return <StepsTimeline items={items} className={className} />;
  }

  // ── Vertical (default) ───────────────────────────────────────────────────
  return (
    <div className={cn("relative", className)}>
      <div
        className="absolute top-0 bottom-0 w-px"
        style={{ left: LINE_LEFT, backgroundColor: resolvedLineColor }}
      />
      <div className="space-y-6">
        {items.map((item, index) => (
          <TimelineNode key={item.id} item={item} index={index} />
        ))}
      </div>
    </div>
  );
}

// ─── Vertical node ───────────────────────────────────────────────────────────

function TimelineNode({ item, index }: { item: TimelineItem; index: number }) {
  const ref = useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once: true, amount: 0.3 });
  const color = item.color || "#a855f7";

  return (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, x: -24 }}
      animate={isInView ? { opacity: 1, x: 0 } : { opacity: 0, x: -24 }}
      transition={{ type: "spring", stiffness: 100, damping: 15, delay: index * 0.1 }}
      className="relative flex items-start"
      style={{ paddingLeft: DOT_SIZE + 16 }}
    >
      {/* Colored circle */}
      <motion.div
        initial={{ scale: 0 }}
        animate={isInView ? { scale: 1 } : { scale: 0 }}
        transition={{ type: "spring", stiffness: 320, damping: 22, delay: index * 0.1 + 0.08 }}
        className="absolute z-10 flex items-center justify-center rounded-full"
        style={{
          width: DOT_SIZE, height: DOT_SIZE, left: 0, top: 2,
          background: `radial-gradient(circle at 35% 35%, ${color}cc, ${color}88)`,
          boxShadow: `0 0 0 3px ${color}22, 0 0 12px ${color}55`,
          border: `2px solid ${color}99`,
        }}
      >
        {item.icon
          ? <span className="text-[11px] leading-none">{item.icon}</span>
          : <div className="h-2.5 w-2.5 rounded-full" style={{ backgroundColor: "#fff", opacity: 0.9 }} />
        }
      </motion.div>

      {/* Ripple ring */}
      <motion.div
        initial={{ scale: 0.6, opacity: 0 }}
        animate={isInView ? { scale: 2.2, opacity: 0 } : { scale: 0.6, opacity: 0 }}
        transition={{ delay: index * 0.1 + 0.18, duration: 0.7, ease: "easeOut" }}
        className="absolute z-0 rounded-full"
        style={{ width: DOT_SIZE, height: DOT_SIZE, left: 0, top: 2, border: `1.5px solid ${color}` }}
      />

      {/* Text */}
      <div className="flex-1 min-w-0 pb-1">
        {item.date && <span className="text-[11px] text-neutral-500 mb-0.5 block">{item.date}</span>}
        <h4 className="text-sm font-semibold text-white leading-snug">{item.title}</h4>
        {item.description && (
          <p className="text-xs text-neutral-400 mt-1 leading-relaxed">{item.description}</p>
        )}
      </div>
    </motion.div>
  );
}

// ─── Horizontal timeline ──────────────────────────────────────────────────────
// Animation: connecting line grows left-to-right, dots pop in with spring

function HorizontalTimeline({ items, className, lineColor, theme: _theme = "dark" }: {
  items: TimelineItem[]; className?: string; lineColor: string; theme?: "light" | "dark";
}) {
  const ref = useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once: true, amount: 0.3 });

  return (
    <div ref={ref} className={cn("overflow-x-auto", className)}>
      <div className="flex min-w-max pb-4">
        {items.map((item, index) => {
          const color = item.color || "#a855f7";
          const isFirst = index === 0;
          const isLast = index === items.length - 1;

          return (
            <motion.div
              key={item.id}
              initial={{ opacity: 0, y: 16 }}
              animate={isInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 16 }}
              transition={{ type: "spring", stiffness: 100, damping: 16, delay: index * 0.15 }}
              className="flex flex-col items-center w-[200px]"
            >
              {/* ── Top row: left-half | dot | right-half ─────────────────── */}
              <div className="flex w-full items-center">

                {/* Left connector half — empty on first item */}
                <div className="flex-1 overflow-hidden" style={{ height: 1 }}>
                  {!isFirst && (
                    <motion.div
                      className="h-full w-full origin-right"
                      style={{ backgroundColor: lineColor }}
                      initial={{ scaleX: 0 }}
                      animate={isInView ? { scaleX: 1 } : { scaleX: 0 }}
                      transition={{ duration: 0.4, ease: [0.23, 1, 0.32, 1], delay: index * 0.15 + 0.05 }}
                    />
                  )}
                </div>

                {/* Dot */}
                <motion.div
                  initial={{ scale: 0 }}
                  animate={isInView ? { scale: 1 } : { scale: 0 }}
                  transition={{ type: "spring", stiffness: 320, damping: 22, delay: index * 0.15 + 0.1 }}
                  className="relative z-10 flex items-center justify-center rounded-full flex-shrink-0"
                  style={{
                    width: DOT_SIZE, height: DOT_SIZE,
                    background: `radial-gradient(circle at 35% 35%, ${color}cc, ${color}88)`,
                    boxShadow: `0 0 0 3px ${color}22, 0 0 12px ${color}55`,
                    border: `2px solid ${color}99`,
                  }}
                >
                  {item.icon
                    ? <span className="text-[11px] leading-none">{item.icon}</span>
                    : <div className="h-2.5 w-2.5 rounded-full bg-white/90" />
                  }
                </motion.div>

                {/* Right connector half — empty on last item */}
                <div className="flex-1 overflow-hidden" style={{ height: 1 }}>
                  {!isLast && (
                    <motion.div
                      className="h-full w-full origin-left"
                      style={{ backgroundColor: lineColor }}
                      initial={{ scaleX: 0 }}
                      animate={isInView ? { scaleX: 1 } : { scaleX: 0 }}
                      transition={{ duration: 0.4, ease: [0.23, 1, 0.32, 1], delay: index * 0.15 + 0.15 }}
                    />
                  )}
                </div>
              </div>

              {/* ── Text below dot ────────────────────────────────────────── */}
              <div className="text-center mt-4 px-1">
                {item.date && <span className="text-[11px] text-neutral-500 mb-0.5 block">{item.date}</span>}
                <h4 className="text-sm font-semibold text-white leading-snug">{item.title}</h4>
                {item.description && (
                  <p className="text-xs text-neutral-400 mt-1 max-w-[170px]">{item.description}</p>
                )}
              </div>
            </motion.div>
          );
        })}
      </div>
    </div>
  );
}

// ─── Cards timeline ───────────────────────────────────────────────────────────
// Animation: center vertical line, items alternate left/right and slide in

function CardsTimeline({ items, className, lineColor, theme: _theme = "dark" }: {
  items: TimelineItem[]; className?: string; lineColor: string; theme?: "light" | "dark";
}) {
  return (
    <div className={cn("relative", className)}>
      {/* Center vertical line */}
      <div className="absolute top-0 bottom-0 w-px left-1/2 -translate-x-1/2" style={{ backgroundColor: lineColor }} />

      <div className="space-y-8">
        {items.map((item, index) => {
          const isLeft = index % 2 === 0;
          const color = item.color || "#a855f7";
          return (
            <CardsTimelineRow key={item.id} item={item} index={index} isLeft={isLeft} color={color} />
          );
        })}
      </div>
    </div>
  );
}

function CardsTimelineRow({ item, index, isLeft, color }: {
  item: TimelineItem; index: number; isLeft: boolean; color: string;
}) {
  const ref = useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once: true, amount: 0.3 });

  return (
    <motion.div
      ref={ref}
      className="relative grid grid-cols-2 gap-4 items-center"
    >
      {/* Left side: either card or spacer */}
      <div className={cn("flex", isLeft ? "justify-end pr-4" : "justify-start pl-4")}>
        {isLeft ? (
          <motion.div
            initial={{ opacity: 0, x: -32 }}
            animate={isInView ? { opacity: 1, x: 0 } : { opacity: 0, x: -32 }}
            transition={{ type: "spring", stiffness: 90, damping: 16, delay: index * 0.08 }}
            className="max-w-[220px] rounded-xl border border-neutral-800 bg-neutral-950 p-4"
            style={{ borderColor: `${color}22` }}
          >
            <CardContent item={item} color={color} isInView={isInView} index={index} />
          </motion.div>
        ) : null}
      </div>

      {/* Center dot */}
      <motion.div
        initial={{ scale: 0, opacity: 0 }}
        animate={isInView ? { scale: 1, opacity: 1 } : { scale: 0, opacity: 0 }}
        transition={{ type: "spring", stiffness: 300, damping: 20, delay: index * 0.08 + 0.06 }}
        className="absolute left-1/2 -translate-x-1/2 z-10 flex items-center justify-center rounded-full"
        style={{
          width: DOT_SIZE, height: DOT_SIZE,
          background: `radial-gradient(circle at 35% 35%, ${color}cc, ${color}88)`,
          boxShadow: `0 0 0 3px ${color}22, 0 0 14px ${color}55`,
          border: `2px solid ${color}99`,
        }}
      >
        {item.icon
          ? <span className="text-[11px] leading-none">{item.icon}</span>
          : <div className="h-2.5 w-2.5 rounded-full bg-white/90" />
        }
      </motion.div>

      {/* Right side: either spacer or card */}
      <div className={cn("flex", isLeft ? "justify-start pl-4" : "justify-end pr-4")}>
        {!isLeft ? (
          <motion.div
            initial={{ opacity: 0, x: 32 }}
            animate={isInView ? { opacity: 1, x: 0 } : { opacity: 0, x: 32 }}
            transition={{ type: "spring", stiffness: 90, damping: 16, delay: index * 0.08 }}
            className="max-w-[220px] rounded-xl border border-neutral-800 bg-neutral-950 p-4"
            style={{ borderColor: `${color}22` }}
          >
            <CardContent item={item} color={color} isInView={isInView} index={index} />
          </motion.div>
        ) : null}
      </div>
    </motion.div>
  );
}

function CardContent({ item, color, isInView, index }: {
  item: TimelineItem; color: string; isInView: boolean; index: number;
}) {
  return (
    <>
      {item.date && (
        <motion.span
          initial={{ opacity: 0 }}
          animate={isInView ? { opacity: 1 } : { opacity: 0 }}
          transition={{ delay: index * 0.08 + 0.15, duration: 0.3 }}
          className="text-[10px] uppercase tracking-wider mb-1 block"
          style={{ color }}
        >
          {item.date}
        </motion.span>
      )}
      <motion.h4
        initial={{ opacity: 0, y: 6 }}
        animate={isInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 6 }}
        transition={{ type: "spring", stiffness: 120, damping: 16, delay: index * 0.08 + 0.18 }}
        className="text-sm font-semibold text-white"
      >
        {item.title}
      </motion.h4>
      {item.description && (
        <motion.p
          initial={{ opacity: 0 }}
          animate={isInView ? { opacity: 0.6 } : { opacity: 0 }}
          transition={{ delay: index * 0.08 + 0.25, duration: 0.4 }}
          className="text-xs text-neutral-400 mt-1 leading-relaxed"
        >
          {item.description}
        </motion.p>
      )}
    </>
  );
}

// ─── Steps timeline ───────────────────────────────────────────────────────────
// Animation: numbered circle fills radially, connector bar scales width, text blurs in

function StepsTimeline({ items, className, theme: _theme = "dark" }: { items: TimelineItem[]; className?: string; theme?: "light" | "dark" }) {
  return (
    <div className={cn("space-y-0", className)}>
      {items.map((item, index) => (
        <StepNode key={item.id} item={item} index={index} total={items.length} />
      ))}
    </div>
  );
}

function StepNode({ item, index, total }: { item: TimelineItem; index: number; total: number }) {
  const ref = useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once: true, amount: 0.4 });
  const color = item.color || "#a855f7";
  const isLast = index === total - 1;

  return (
    <div ref={ref} className="flex gap-4">
      {/* Left: number + connector */}
      <div className="flex flex-col items-center">
        {/* Numbered circle — fills radially on entry */}
        <motion.div
          initial={{ scale: 0.4, opacity: 0 }}
          animate={isInView ? { scale: 1, opacity: 1 } : { scale: 0.4, opacity: 0 }}
          transition={{ type: "spring", stiffness: 280, damping: 20, delay: index * 0.12 }}
          className="relative z-10 flex items-center justify-center rounded-full flex-shrink-0"
          style={{
            width: 32, height: 32,
            background: `radial-gradient(circle at 40% 40%, ${color}, ${color}99)`,
            boxShadow: `0 0 0 4px ${color}18, 0 0 16px ${color}44`,
          }}
        >
          <motion.span
            initial={{ opacity: 0, scale: 0.5 }}
            animate={isInView ? { opacity: 1, scale: 1 } : { opacity: 0, scale: 0.5 }}
            transition={{ delay: index * 0.12 + 0.1, duration: 0.25 }}
            className="text-xs font-bold text-white tabular-nums"
          >
            {index + 1}
          </motion.span>
        </motion.div>

        {/* Connector bar — scales from top down */}
        {!isLast && (
          <motion.div
            className="w-px flex-1 mt-1 mb-1 origin-top"
            style={{ backgroundColor: `${color}30` }}
            initial={{ scaleY: 0 }}
            animate={isInView ? { scaleY: 1 } : { scaleY: 0 }}
            transition={{ delay: index * 0.12 + 0.2, duration: 0.4, ease: "easeOut" }}
          />
        )}
      </div>

      {/* Right: text */}
      <motion.div
        initial={{ opacity: 0, x: 16, filter: "blur(4px)" }}
        animate={isInView ? { opacity: 1, x: 0, filter: "blur(0px)" } : { opacity: 0, x: 16, filter: "blur(4px)" }}
        transition={{ delay: index * 0.12 + 0.08, duration: 0.38, ease: [0.23, 1, 0.32, 1] }}
        className={cn("flex-1 min-w-0", isLast ? "pb-0" : "pb-6")}
      >
        {item.date && (
          <span className="text-[10px] uppercase tracking-wider block mb-0.5" style={{ color: `${color}bb` }}>
            {item.date}
          </span>
        )}
        <h4 className="text-sm font-semibold text-white">{item.title}</h4>
        {item.description && (
          <p className="text-xs text-neutral-400 mt-1 leading-relaxed">{item.description}</p>
        )}
      </motion.div>
    </div>
  );
}

import { type ClassValue, clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
    return twMerge(clsx(inputs));
}

"use client";
import React, { useState, useRef, useEffect } from "react";
import Image from "next/image";
import {
  motion,
  AnimatePresence,
  useSpring,
} from "motion/react";
import { cn } from "@/lib/utils";

// ─── Types ───────────────────────────────────────────────────────────────────

/**
 * NestedComments is designed for small-to-medium discussion threads.
 * For very large or deeply nested trees, consider centralizing comment state
 * and/or pairing with virtualization to keep rendering work bounded.
 */
export type Comment = {
  id: string;
  author: string;
  avatar?: string;
  content: string;
  timestamp: string;
  likes: number;
  replies?: Comment[];
};

type NestedCommentsProps = {
  comments: Comment[];
  maxDepth?: number;
  className?: string;
  accentColor?: string;
  onReply?: (commentId: string, content: string) => void;
  onLike?: (commentId: string) => void;
  theme?: "light" | "dark";
};

// ─── Avatar ──────────────────────────────────────────────────────────────────

function Avatar({
  author,
  avatar,
  size = 36,
}: {
  author: string;
  avatar?: string;
  size?: number;
}) {
  const initials = author
    .split(" ")
    .map((n) => n[0])
    .join("")
    .slice(0, 2)
    .toUpperCase();

  const colors = [
    "from-violet-500 to-purple-600",
    "from-blue-500 to-cyan-600",
    "from-emerald-500 to-teal-600",
    "from-amber-500 to-orange-600",
    "from-rose-500 to-pink-600",
    "from-indigo-500 to-blue-600",
  ];
  const color = colors[author.charCodeAt(0) % colors.length];

  return (
    <div
      className="relative flex-shrink-0 rounded-full overflow-hidden ring-2 ring-white/10"
      style={{ width: size, height: size }}
    >
      {avatar ? (
        <Image src={avatar} alt={author} fill className="object-cover" />
      ) : (
        <div
          className={cn("w-full h-full flex items-center justify-center bg-gradient-to-br", color)}
        >
          <span className="text-white font-semibold" style={{ fontSize: size * 0.35 }}>
            {initials}
          </span>
        </div>
      )}
    </div>
  );
}

// ─── Like Button ─────────────────────────────────────────────────────────────

function LikeButton({
  count,
  onLike,
  accentColor: _accentColor,
}: {
  count: number;
  onLike?: () => void;
  accentColor: string;
}) {
  const [liked, setLiked] = useState(false);
  const [displayCount, setDisplayCount] = useState(count);
  const scale = useSpring(1, { stiffness: 600, damping: 15 });

  const handleLike = () => {
    if (liked) return;
    setLiked(true);
    setDisplayCount((c) => c + 1);
    scale.set(1.4);
    setTimeout(() => scale.set(1), 200);
    onLike?.();
  };

  return (
    <button
      onClick={handleLike}
      aria-label={`Like comment, ${displayCount} likes`}
      className={cn(
        "flex items-center gap-1.5 text-xs font-medium px-2.5 py-1 rounded-full transition-all duration-200",
        liked
          ? "text-rose-400 bg-rose-500/10"
          : "text-neutral-500 hover:text-neutral-300 hover:bg-white/5"
      )}
    >
      <motion.span style={{ scale }} className="inline-flex">
        <svg
          viewBox="0 0 24 24"
          fill={liked ? "currentColor" : "none"}
          stroke="currentColor"
          strokeWidth={2}
          className="w-3.5 h-3.5"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            d="M21 8.25c0-2.485-2.099-4.5-4.688-4.5-1.935 0-3.597 1.126-4.312 2.733-.715-1.607-2.377-2.733-4.313-2.733C5.1 3.75 3 5.765 3 8.25c0 7.22 9 12 9 12s9-4.78 9-12z"
          />
        </svg>
      </motion.span>
      <AnimatePresence mode="popLayout">
        <motion.span
          key={displayCount}
          initial={{ y: -8, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: 8, opacity: 0 }}
          transition={{ duration: 0.15 }}
        >
          {displayCount}
        </motion.span>
      </AnimatePresence>
    </button>
  );
}

// ─── Reply Box ────────────────────────────────────────────────────────────────

function ReplyBox({
  onSubmit,
  onCancel,
  accentColor: _accentColor,
}: {
  onSubmit: (text: string) => void;
  onCancel: () => void;
  accentColor: string;
}) {
  const [text, setText] = useState("");
  const ref = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    ref.current?.focus();
  }, []);

  const handleKey = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && (e.metaKey || e.ctrlKey) && text.trim()) {
      onSubmit(text.trim());
    }
    if (e.key === "Escape") onCancel();
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: -8, scaleY: 0.9 }}
      animate={{ opacity: 1, y: 0, scaleY: 1 }}
      exit={{ opacity: 0, y: -8, scaleY: 0.9 }}
      transition={{ duration: 0.2, ease: [0.23, 1, 0.32, 1] }}
      style={{ transformOrigin: "top" }}
      className="mt-2 rounded-xl border border-white/10 bg-white/5 overflow-hidden"
    >
      <textarea
        ref={ref}
        value={text}
        onChange={(e) => setText(e.target.value)}
        onKeyDown={handleKey}
        placeholder="Write a reply… (⌘+Enter to send, Esc to cancel)"
        rows={2}
        className="w-full bg-transparent px-3 pt-3 pb-1 text-sm text-neutral-200 placeholder-neutral-600 resize-none outline-none"
      />
      <div className="flex items-center justify-between px-3 pb-2 gap-2">
        <span className="text-xs text-neutral-600">⌘+Enter to submit</span>
        <div className="flex gap-2">
          <button
            onClick={onCancel}
            className="px-3 py-1 text-xs rounded-lg text-neutral-500 hover:text-neutral-300 hover:bg-white/5 transition-colors"
          >
            Cancel
          </button>
          <motion.button
            whileTap={{ scale: 0.95 }}
            onClick={() => text.trim() && onSubmit(text.trim())}
            disabled={!text.trim()}
            className={cn(
              "px-3 py-1 text-xs rounded-lg font-medium transition-all duration-200",
              text.trim()
                ? "text-white bg-violet-600 hover:bg-violet-500"
                : "text-neutral-600 bg-white/5 cursor-not-allowed"
            )}
          >
            Reply
          </motion.button>
        </div>
      </div>
    </motion.div>
  );
}

// ─── Connector Line ───────────────────────────────────────────────────────────

function _ConnectorLine({ height }: { height: number }) {
  return (
    <motion.div
      initial={{ scaleY: 0 }}
      animate={{ scaleY: 1 }}
      transition={{ duration: 0.3, ease: "easeOut", delay: 0.1 }}
      style={{ transformOrigin: "top", height }}
      className="absolute left-0 top-0 w-px bg-gradient-to-b from-white/20 via-white/10 to-transparent"
    />
  );
}

// ─── Single Comment ───────────────────────────────────────────────────────────

function CommentNode({
  comment,
  depth,
  maxDepth,
  accentColor,
  onReply,
  onLike,
  isLast: _isLast,
}: {
  comment: Comment;
  depth: number;
  maxDepth: number;
  accentColor: string;
  onReply?: (id: string, content: string) => void;
  onLike?: (id: string) => void;
  isLast: boolean;
}) {
  const [replying, setReplying] = useState(false);
  const [collapsed, setCollapsed] = useState(false);
  const [localReplies, setLocalReplies] = useState<Comment[]>(comment.replies ?? []);
  const containerRef = useRef<HTMLDivElement>(null);
  const hasReplies = localReplies.length > 0;
  const canReply = depth < maxDepth;
  const avatarSize = depth === 0 ? 36 : 28;

  const handleReply = (content: string) => {
    const newReply: Comment = {
      id: `local-${Date.now()}`,
      author: "You",
      content,
      timestamp: "just now",
      likes: 0,
    };
    setLocalReplies((prev) => [...prev, newReply]);
    setReplying(false);
    setCollapsed(false);
    onReply?.(comment.id, content);
  };

  return (
    <motion.div
      layout
      initial={{ opacity: 0, x: -12 }}
      animate={{ opacity: 1, x: 0 }}
      transition={{ duration: 0.28, ease: [0.23, 1, 0.32, 1] }}
      ref={containerRef}
      className="relative"
    >
      {/* Main comment row */}
      <div className="flex gap-3">
        {/* Avatar + thread line column */}
        <div className="relative flex flex-col items-center">
          <Avatar author={comment.author} avatar={comment.avatar} size={avatarSize} />
          {/* Vertical thread line */}
          {hasReplies && !collapsed && (
            <div className="flex-1 mt-1.5 w-px bg-gradient-to-b from-white/15 via-white/8 to-transparent min-h-[16px]" />
          )}
        </div>

        {/* Comment body */}
        <div className="flex-1 min-w-0 pb-3">
          {/* Header */}
          <div className="flex items-baseline gap-2 flex-wrap mb-1.5">
            <span className="text-sm font-semibold text-neutral-100">{comment.author}</span>
            <span className="text-xs text-neutral-600">{comment.timestamp}</span>
            {depth > 0 && (
              <span
                className="text-xs px-1.5 py-0.5 rounded-full"
                style={{ background: `${accentColor}20`, color: accentColor }}
              >
                reply
              </span>
            )}
          </div>

          {/* Content */}
          <p className="text-sm text-neutral-300 leading-relaxed mb-2">
            {comment.content}
          </p>

          {/* Action bar */}
          <div className="flex items-center gap-1 flex-wrap">
            <LikeButton
              count={comment.likes}
              onLike={() => onLike?.(comment.id)}
              accentColor={accentColor}
            />

            {canReply && (
              <motion.button
                whileTap={{ scale: 0.95 }}
                onClick={() => setReplying((v) => !v)}
                aria-label={`Reply to ${comment.author}`}
                className="flex items-center gap-1.5 text-xs font-medium px-2.5 py-1 rounded-full text-neutral-500 hover:text-neutral-300 hover:bg-white/5 transition-all duration-200"
              >
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} className="w-3.5 h-3.5">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" />
                </svg>
                Reply
              </motion.button>
            )}

            {hasReplies && (
              <motion.button
                whileTap={{ scale: 0.95 }}
                onClick={() => setCollapsed((v) => !v)}
                className="flex items-center gap-1.5 text-xs font-medium px-2.5 py-1 rounded-full text-neutral-500 hover:text-neutral-300 hover:bg-white/5 transition-all duration-200"
              >
                <motion.svg
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth={2}
                  className="w-3.5 h-3.5"
                  animate={{ rotate: collapsed ? -90 : 0 }}
                  transition={{ duration: 0.2 }}
                >
                  <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
                </motion.svg>
                {collapsed
                  ? `${localReplies.length} repl${localReplies.length === 1 ? "y" : "ies"}`
                  : "Collapse"}
              </motion.button>
            )}
          </div>

          {/* Reply box */}
          <AnimatePresence>
            {replying && (
              <ReplyBox
                onSubmit={handleReply}
                onCancel={() => setReplying(false)}
                accentColor={accentColor}
              />
            )}
          </AnimatePresence>
        </div>
      </div>

      {/* Nested replies */}
      <AnimatePresence>
        {hasReplies && !collapsed && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: "auto" }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.28, ease: [0.23, 1, 0.32, 1] }}
            className="ml-[18px] pl-5 border-l border-white/10 overflow-hidden"
          >
            {localReplies.map((reply, i) => (
              <CommentNode
                key={reply.id}
                comment={reply}
                depth={depth + 1}
                maxDepth={maxDepth}
                accentColor={accentColor}
                onReply={onReply}
                onLike={onLike}
                isLast={i === localReplies.length - 1}
              />
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
}

// ─── Root Component ───────────────────────────────────────────────────────────

export function NestedComments({
  comments,
  maxDepth = 4,
  className,
  accentColor = "#8b5cf6",
  onReply,
  onLike,
  theme = "dark",
}: NestedCommentsProps) {
  const [localComments, setLocalComments] = useState<Comment[]>(comments);
  const [newComment, setNewComment] = useState("");
  const [posting, setPosting] = useState(false);
  const count = localComments.length;
  const isDark = theme === "dark";

  const handlePost = () => {
    if (!newComment.trim()) return;
    const c: Comment = {
      id: `local-root-${Date.now()}`,
      author: "You",
      content: newComment.trim(),
      timestamp: "just now",
      likes: 0,
    };
    setPosting(true);
    setTimeout(() => {
      setLocalComments((prev) => [c, ...prev]);
      setNewComment("");
      setPosting(false);
    }, 300);
  };

  return (
    <div aria-label="Comments" className={cn("w-full max-w-2xl mx-auto", className)}>
      {/* Header */}
      <div className="flex items-center gap-2 mb-5">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} className={cn("w-5 h-5", isDark ? "text-neutral-400" : "text-neutral-500")}>
          <path strokeLinecap="round" strokeLinejoin="round" d="M7.5 8.25h9m-9 3H12m-9.75 1.51c0 1.6 1.123 2.994 2.707 3.227 1.129.166 2.27.293 3.423.379.35.026.67.21.865.501L12 21l2.755-4.133a1.14 1.14 0 01.865-.501 48.172 48.172 0 003.423-.379c1.584-.233 2.707-1.626 2.707-3.228V6.741c0-1.602-1.123-2.995-2.707-3.228A48.394 48.394 0 0012 3c-2.392 0-4.744.175-7.043.513C3.373 3.746 2.25 5.14 2.25 6.741v6.018z" />
        </svg>
        <span className={cn("text-base font-semibold", isDark ? "text-neutral-200" : "text-neutral-800")}>
          {count} {count === 1 ? "Comment" : "Comments"}
        </span>
      </div>

      {/* New comment composer */}
      <div className={cn("mb-6 rounded-xl border overflow-hidden", isDark ? "border-white/10 bg-white/[0.03]" : "border-neutral-200 bg-neutral-50")}>
        <textarea
          aria-label="Write a new comment"
          value={newComment}
          onChange={(e) => setNewComment(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) handlePost();
          }}
          placeholder="Share your thoughts… (⌘+Enter to post)"
          rows={3}
          className={cn("w-full bg-transparent px-4 pt-4 pb-2 text-sm resize-none outline-none", isDark ? "text-neutral-200 placeholder-neutral-600" : "text-neutral-800 placeholder-neutral-500")}
        />
        <div className="flex items-center justify-between px-4 pb-3">
          <span className={cn("text-xs", isDark ? "text-neutral-600" : "text-neutral-500")}>{newComment.length > 0 ? `${newComment.length} chars` : "⌘+Enter to post"}</span>
          <motion.button
            whileTap={{ scale: 0.95 }}
            animate={posting ? { scale: [1, 0.97, 1] } : {}}
            onClick={handlePost}
            disabled={!newComment.trim() || posting}
            className={cn(
              "px-4 py-1.5 text-xs rounded-lg font-semibold transition-all duration-200",
              newComment.trim() && !posting
                ? "text-white bg-violet-600 hover:bg-violet-500"
                : isDark ? "text-neutral-600 bg-white/5 cursor-not-allowed" : "text-neutral-500 bg-neutral-200 cursor-not-allowed"
            )}
          >
            {posting ? "Posting…" : "Post comment"}
          </motion.button>
        </div>
      </div>

      {/* Comment list */}
      <motion.div layout className="space-y-1">
        <AnimatePresence initial={false}>
          {localComments.map((comment, i) => (
            <CommentNode
              key={comment.id}
              comment={comment}
              depth={0}
              maxDepth={maxDepth}
              accentColor={accentColor}
              onReply={onReply}
              onLike={onLike}
              isLast={i === localComments.length - 1}
            />
          ))}
        </AnimatePresence>

        {localComments.length === 0 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className={cn("text-center py-12 text-sm", isDark ? "text-neutral-600" : "text-neutral-500")}
          >
            No comments yet. Be the first to share your thoughts!
          </motion.div>
        )}
      </motion.div>
    </div>
  );
}

